// Package cluster_test verifies that the binary wire format produced by
// cluster/pubsub matches Pekko's DistributedPubSubMessageSerializer exactly,
// using binary fixtures generated by the real JVM serializer.
//
// Fixtures are generated by:
//
//	cd scala-server && sbt "runMain org.apache.pekko.cluster.pubsub.PubSubBinaryGenerator ../cluster/testdata"
//
// Wire format reference (Pekko source):
//
//	cluster-tools/src/main/scala/org/apache/pekko/cluster/pubsub/protobuf/DistributedPubSubMessageSerializer.scala
//	cluster-tools/src/main/protobuf/DistributedPubSubMessages.proto
//
// Pekko serializer ID: 9
// Manifests: "A"=Status(GZIP), "B"=Delta(GZIP), "C"=Send, "D"=SendToAll, "E"=Publish, "F"=SendToOneSubscriber
//
// Test fixture contents (from Scala generator):
//
//	pubsub_publish.bin              Publish("news", "Hello" as bytes)          17 bytes
//	pubsub_send.bin                 Send("/user/handler", [1,2,3,4], true)     27 bytes
//	pubsub_sendtoall.bin            SendToAll("/user/all", [5,6,7], false)     22 bytes
//	pubsub_sendtoonesubscriber.bin  SendToOneSubscriber([9,10,11])             9 bytes
//	pubsub_status.bin               Status(Map(addr->42), replyToStatus=true)  56 bytes GZIP
//	pubsub_delta.bin                Delta(Bucket(addr,3,{"/news"->VH(2,"")}))  65 bytes GZIP
//
// ID 9 conflict note:
//
//	Pekko assigns ID 9 to DistributedPubSubMessageSerializer.
//	Gekka's internal JSONSerializer also uses ID 9 for CRDT gossip between Go-only nodes.
//	Enabling Pekko pub-sub interop requires registering PubSubSerializer at ID 9,
//	superseding the JSON serializer in the SerializationRegistry for that node.
package cluster_test

import (
	"bytes"
	"compress/gzip"
	"io"
	"os"
	"testing"

	"github.com/sopranoworks/gekka/cluster/pubsub"
)

const fixtureDir = "testdata"

// loadFixture reads a binary fixture from the testdata directory.
// The test is skipped — not failed — if the fixture has not yet been generated,
// with instructions for how to produce it.
func loadFixture(t *testing.T, name string) []byte {
	t.Helper()
	path := fixtureDir + "/" + name
	data, err := os.ReadFile(path)
	if err != nil {
		if os.IsNotExist(err) {
			t.Skipf(
				"fixture %q not found — generate with:\n"+
					"  cd scala-server && sbt \"runMain org.apache.pekko.cluster.pubsub.PubSubBinaryGenerator ../cluster/testdata\"",
				path,
			)
		}
		t.Fatalf("loadFixture %s: %v", path, err)
	}
	return data
}

// gzipDecompress decompresses GZIP data, used to compare inner proto bytes.
func gzipDecompress(data []byte) ([]byte, error) {
	r, err := gzip.NewReader(bytes.NewReader(data))
	if err != nil {
		return nil, err
	}
	defer r.Close()
	return io.ReadAll(r)
}

// isGzip returns true if data starts with the GZIP magic bytes.
func isGzip(data []byte) bool {
	return len(data) >= 2 && data[0] == 0x1f && data[1] == 0x8b
}

// ---------------------------------------------------------------------------
// Serializer ID and manifest constants
// ---------------------------------------------------------------------------

// TestPubSubSerializerID verifies the serializer ID matches Pekko's assignment.
//
// Source: cluster-tools/src/main/resources/reference.conf
//
//	serialization-identifiers {
//	  "org.apache.pekko.cluster.pubsub.protobuf.DistributedPubSubMessageSerializer" = 9
//	}
func TestPubSubSerializerID(t *testing.T) {
	const want = int32(9)
	if pubsub.PubSubSerializerID != want {
		t.Errorf("PubSubSerializerID = %d, want %d", pubsub.PubSubSerializerID, want)
	}
}

// TestPubSubManifests verifies all six manifest codes match Pekko exactly.
// Source: DistributedPubSubMessageSerializer.scala, StatusManifest through SendToOneSubscriberManifest.
func TestPubSubManifests(t *testing.T) {
	cases := []struct{ name, got, want string }{
		{"Status", pubsub.StatusManifest, "A"},
		{"Delta", pubsub.DeltaManifest, "B"},
		{"Send", pubsub.SendManifest, "C"},
		{"SendToAll", pubsub.SendToAllManifest, "D"},
		{"Publish", pubsub.PublishManifest, "E"},
		{"SendToOneSubscriber", pubsub.SendToOneSubscriberManifest, "F"},
	}
	for _, c := range cases {
		if c.got != c.want {
			t.Errorf("%s manifest = %q, want %q", c.name, c.got, c.want)
		}
	}
}

// ---------------------------------------------------------------------------
// Publish (manifest "E") — plain Protobuf, 17 bytes
//
// Proto schema:
//   message Publish {
//     required string topic   = 1;
//     required Payload payload = 3;   // field 3, not 2
//   }
//
// Fixture: Publish("news", Array[Byte]("Hello")), payload via ByteArraySerializer (ID=4)
// ---------------------------------------------------------------------------

// TestPublish_ScalaDecode verifies Go can decode Pekko-generated Publish bytes.
func TestPublish_ScalaDecode(t *testing.T) {
	scalaBytes := loadFixture(t, "pubsub_publish.bin")

	if isGzip(scalaBytes) {
		t.Fatal("Publish fixture must NOT be GZIP-compressed (Pekko sends plain Protobuf for Publish)")
	}

	s := &pubsub.PubSubSerializer{}
	topic, msg, serializerID, manifest, err := s.DecodePublish(scalaBytes)
	if err != nil {
		t.Fatalf("DecodePublish: %v", err)
	}
	if topic != "news" {
		t.Errorf("topic = %q, want %q", topic, "news")
	}
	if !bytes.Equal(msg, []byte("Hello")) {
		t.Errorf("enclosedMessage = %v, want %q", msg, "Hello")
	}
	if serializerID != 4 {
		t.Errorf("serializerID = %d, want 4 (ByteArraySerializer)", serializerID)
	}
	if manifest != "" {
		t.Errorf("manifest = %q, want empty (ByteArraySerializer.includeManifest=false)", manifest)
	}
}

// TestPublish_GoMatchesScala verifies Go-encoded bytes are identical to Pekko's output.
// This is a strict byte-level comparison for plain Protobuf (no GZIP non-determinism).
func TestPublish_GoMatchesScala(t *testing.T) {
	scalaBytes := loadFixture(t, "pubsub_publish.bin")

	s := &pubsub.PubSubSerializer{}
	goBytes, err := s.EncodePublish("news", []byte("Hello"), 4, "")
	if err != nil {
		t.Fatalf("EncodePublish: %v", err)
	}

	if !bytes.Equal(goBytes, scalaBytes) {
		t.Errorf("Go-encoded Publish does NOT match Pekko output:\n  Go  (%d bytes): %x\n  JVM (%d bytes): %x",
			len(goBytes), goBytes, len(scalaBytes), scalaBytes)
	}
}

// TestPublish_PayloadAtFieldThree verifies the payload is at proto field 3, not field 2.
// This is a critical correctness check — DistributedPubSubMessages.proto defines:
//
//	message Publish {
//	  required string topic   = 1;
//	  required Payload payload = 3;   // field 3!
//	}
func TestPublish_PayloadAtFieldThree(t *testing.T) {
	scalaBytes := loadFixture(t, "pubsub_publish.bin")
	// Layout: 0x0a <len> "news" <tag> ...
	// After "0a 04 news" (6 bytes), the next tag byte must be 0x1a = (3<<3)|2
	if len(scalaBytes) < 7 {
		t.Fatalf("fixture too short: %v", scalaBytes)
	}
	topicTagLen := 2 + 4 // tag + len-byte + "news"
	payloadTag := scalaBytes[topicTagLen]
	const want = byte(0x1a) // field 3, wireBytes
	if payloadTag != want {
		t.Errorf("payload tag = 0x%02x, want 0x1a (field 3, wireBytes); "+
			"Pekko's Publish proto defines payload at field 3", payloadTag)
	}
}

