// ---------------------------------------------------------------------------
// Status (manifest "A") — GZIP-compressed Protobuf, 56 bytes
//
// Proto schema:
//   message Status {
//     repeated Version versions    = 1;  // Version{ Address, int64 }
//     optional bool replyToStatus  = 2;
//   }
//
// Fixture: Status(Map(Address("pekko","TestSys","127.0.0.1",2551) -> 42L), replyToStatus=true)
//
// Because GZIP output is non-deterministic across JVM/Go implementations
// (different Deflate engines may produce different compressed bytes for the same input),
// the byte-level comparison is performed on the DECOMPRESSED inner proto bytes, which
// ARE deterministic for a single-entry map with a fully deterministic field order.
// ---------------------------------------------------------------------------

func TestStatus_ScalaIsGzip(t *testing.T) {
	scalaBytes := loadFixture(t, "pubsub_status.bin")
	if !isGzip(scalaBytes) {
		t.Error("Status fixture must be GZIP-compressed (Pekko's compress() call)")
	}
}

func TestStatus_ScalaDecode(t *testing.T) {
	scalaBytes := loadFixture(t, "pubsub_status.bin")

	s := &pubsub.PubSubSerializer{}
	st, err := s.DecodeStatus(scalaBytes)
	if err != nil {
		t.Fatalf("DecodeStatus: %v", err)
	}

	if len(st.Versions) != 1 {
		t.Fatalf("Versions len = %d, want 1", len(st.Versions))
	}
	if !st.IsReplyToStatus {
		t.Error("IsReplyToStatus should be true")
	}

	for addr, ts := range st.Versions {
		if addr.System != "TestSys" {
			t.Errorf("addr.System = %q, want TestSys", addr.System)
		}
		if addr.Hostname != "127.0.0.1" {
			t.Errorf("addr.Hostname = %q, want 127.0.0.1", addr.Hostname)
		}
		if addr.Port != 2551 {
			t.Errorf("addr.Port = %d, want 2551", addr.Port)
		}
		if addr.Protocol != "pekko" {
			t.Errorf("addr.Protocol = %q, want pekko", addr.Protocol)
		}
		if ts != 42 {
			t.Errorf("timestamp = %d, want 42", ts)
		}
	}
}

// TestStatus_InnerProtoMatchesScala compares the decompressed inner proto bytes.
// GZIP bytes from JVM and Go may differ (different Deflate engines); the inner
// proto bytes must be identical for the same message.
func TestStatus_InnerProtoMatchesScala(t *testing.T) {
	scalaBytes := loadFixture(t, "pubsub_status.bin")

	// Decode the Scala fixture to recover the Status value.
	s := &pubsub.PubSubSerializer{}
	st, err := s.DecodeStatus(scalaBytes)
	if err != nil {
		t.Fatalf("DecodeStatus (scala): %v", err)
	}

	// Re-encode with Go serializer.
	goBytes, err := s.EncodeStatus(st)
	if err != nil {
		t.Fatalf("EncodeStatus (go): %v", err)
	}

	// Decompress both and compare inner proto bytes.
	scalaProto, err := gzipDecompress(scalaBytes)
	if err != nil {
		t.Fatalf("gzipDecompress(scala): %v", err)
	}
	goProto, err := gzipDecompress(goBytes)
	if err != nil {
		t.Fatalf("gzipDecompress(go): %v", err)
	}

	if !bytes.Equal(goProto, scalaProto) {
		t.Errorf("Inner proto bytes mismatch (GZIP wrappers may differ between JVM/Go):\n"+
			"  Go  (%d bytes): %x\n"+
			"  JVM (%d bytes): %x",
			len(goProto), goProto, len(scalaProto), scalaProto)
	}
}

// ---------------------------------------------------------------------------
// Delta (manifest "B") — GZIP-compressed Protobuf, 65 bytes
//
// Proto schema:
//   message Delta {
//     repeated Bucket buckets = 1;
//     message Entry  { required string key=1; required int64 version=2; optional string ref=3; }
//     message Bucket { required Address owner=1; required int64 version=2; repeated Entry content=3; }
//   }
//
// Fixture: Delta(List(Bucket(testAddr, 3, TreeMap("/news" -> ValueHolder(2, None)))))
// None ref means field 3 (ref) is absent from the Entry proto.
// ---------------------------------------------------------------------------

func TestDelta_ScalaIsGzip(t *testing.T) {
	scalaBytes := loadFixture(t, "pubsub_delta.bin")
	if !isGzip(scalaBytes) {
		t.Error("Delta fixture must be GZIP-compressed (Pekko's compress() call)")
	}
}

func TestDelta_ScalaDecode(t *testing.T) {
	scalaBytes := loadFixture(t, "pubsub_delta.bin")

	s := &pubsub.PubSubSerializer{}
	d, err := s.DecodeDelta(scalaBytes)
	if err != nil {
		t.Fatalf("DecodeDelta: %v", err)
	}

	if len(d.Buckets) != 1 {
		t.Fatalf("Buckets len = %d, want 1", len(d.Buckets))
	}
	b := d.Buckets[0]
	if b.Owner.System != "TestSys" {
		t.Errorf("Bucket.Owner.System = %q, want TestSys", b.Owner.System)
	}
	if b.Owner.Hostname != "127.0.0.1" {
		t.Errorf("Bucket.Owner.Hostname = %q, want 127.0.0.1", b.Owner.Hostname)
	}
	if b.Owner.Port != 2551 {
		t.Errorf("Bucket.Owner.Port = %d, want 2551", b.Owner.Port)
	}
	if b.Owner.Protocol != "pekko" {
		t.Errorf("Bucket.Owner.Protocol = %q, want pekko", b.Owner.Protocol)
	}
	if b.Version != 3 {
		t.Errorf("Bucket.Version = %d, want 3", b.Version)
	}
	if len(b.Content) != 1 {
		t.Fatalf("Bucket.Content len = %d, want 1", len(b.Content))
	}
	vh, ok := b.Content["/news"]
	if !ok {
		t.Fatal("missing /news entry in Bucket.Content")
	}
	if vh.Version != 2 {
		t.Errorf("/news.version = %d, want 2", vh.Version)
	}
	if vh.Ref != "" {
		t.Errorf("/news.ref = %q, want empty (None in Scala → absent field 3 in proto)", vh.Ref)
	}
}

// TestDelta_InnerProtoMatchesScala compares decompressed inner proto bytes.
func TestDelta_InnerProtoMatchesScala(t *testing.T) {
	scalaBytes := loadFixture(t, "pubsub_delta.bin")

	s := &pubsub.PubSubSerializer{}
	d, err := s.DecodeDelta(scalaBytes)
	if err != nil {
		t.Fatalf("DecodeDelta (scala): %v", err)
	}

	goBytes, err := s.EncodeDelta(d)
	if err != nil {
		t.Fatalf("EncodeDelta (go): %v", err)
	}

	scalaProto, err := gzipDecompress(scalaBytes)
	if err != nil {
		t.Fatalf("gzipDecompress(scala): %v", err)
	}
	goProto, err := gzipDecompress(goBytes)
	if err != nil {
		t.Fatalf("gzipDecompress(go): %v", err)
	}

	if !bytes.Equal(goProto, scalaProto) {
		t.Errorf("Inner proto bytes mismatch:\n  Go  (%d bytes): %x\n  JVM (%d bytes): %x",
			len(goProto), goProto, len(scalaProto), scalaProto)
	}
}

// ---------------------------------------------------------------------------
// Compression boundary: exactly which messages are GZIP'd
// Verified against actual Pekko output, not just spec comments.
// ---------------------------------------------------------------------------

// TestCompressionBoundary_FromFixtures asserts GZIP presence/absence for all
// six message types by inspecting the actual Scala-generated fixture files.
func TestCompressionBoundary_FromFixtures(t *testing.T) {
	cases := []struct {
		fixture string
		gzipped bool
		note    string
	}{
		{"pubsub_status.bin", true, "Status manifest A: compress(statusToProto(m))"},
		{"pubsub_delta.bin", true, "Delta manifest B: compress(deltaToProto(m))"},
		{"pubsub_send.bin", false, "Send manifest C: sendToProto(m).toByteArray"},
		{"pubsub_sendtoall.bin", false, "SendToAll manifest D: sendToAllToProto(m).toByteArray"},
		{"pubsub_publish.bin", false, "Publish manifest E: publishToProto(m).toByteArray"},
		{"pubsub_sendtoonesubscriber.bin", false, "SendToOneSubscriber manifest F: .toByteArray"},
	}
	for _, c := range cases {
		t.Run(c.fixture, func(t *testing.T) {
			data := loadFixture(t, c.fixture)
			if isGzip(data) != c.gzipped {
				if c.gzipped {
					t.Errorf("%s: expected GZIP-compressed (%s)", c.fixture, c.note)
				} else {
					t.Errorf("%s: expected plain Protobuf — NOT GZIP (%s)", c.fixture, c.note)
				}
			}
		})
	}
}

// ---------------------------------------------------------------------------
// Round-trip sanity: Go encodes → Go decodes → values match original
// (Independent of Scala fixtures; verifies internal consistency)
// ---------------------------------------------------------------------------

func TestPublish_RoundTrip(t *testing.T) {
	s := &pubsub.PubSubSerializer{}
	enc, err := s.EncodePublish("events", []byte{0xde, 0xad, 0xbe, 0xef}, 2, "MyProto")
	if err != nil {
		t.Fatalf("EncodePublish: %v", err)
	}
	topic, msg, id, manifest, err := s.DecodePublish(enc)
	if err != nil {
		t.Fatalf("DecodePublish: %v", err)
	}
	if topic != "events" || !bytes.Equal(msg, []byte{0xde, 0xad, 0xbe, 0xef}) || id != 2 || manifest != "MyProto" {
		t.Errorf("round-trip mismatch: topic=%q msg=%v id=%d manifest=%q", topic, msg, id, manifest)
	}
}

func TestStatus_RoundTrip(t *testing.T) {
	s := &pubsub.PubSubSerializer{}
	st := pubsub.Status{
		Versions: map[pubsub.Address]int64{
			{System: "sys", Hostname: "h1", Port: 2551, Protocol: "pekko"}: 99,
		},
		IsReplyToStatus: false,
	}
	enc, err := s.EncodeStatus(st)
	if err != nil {
		t.Fatalf("EncodeStatus: %v", err)
	}
	got, err := s.DecodeStatus(enc)
	if err != nil {
		t.Fatalf("DecodeStatus: %v", err)
	}
	if got.IsReplyToStatus != false || len(got.Versions) != 1 {
		t.Errorf("round-trip mismatch: %+v", got)
	}
}

func TestDelta_EmptyRef_RoundTrip(t *testing.T) {
	s := &pubsub.PubSubSerializer{}
	d := pubsub.Delta{
		Buckets: []pubsub.Bucket{
			{
				Owner:   pubsub.Address{System: "s", Hostname: "h", Port: 1, Protocol: "pekko"},
				Version: 7,
				Content: map[string]pubsub.ValueHolder{
					"/topic": {Version: 3, Ref: ""},                       // None in Scala
					"/group": {Version: 5, Ref: "pekko://s@h:1/user/sub"}, // Some(ref) in Scala
				},
			},
		},
	}
	enc, err := s.EncodeDelta(d)
	if err != nil {
		t.Fatalf("EncodeDelta: %v", err)
	}
	got, err := s.DecodeDelta(enc)
	if err != nil {
		t.Fatalf("DecodeDelta: %v", err)
	}
	if len(got.Buckets) != 1 || len(got.Buckets[0].Content) != 2 {
		t.Fatalf("round-trip mismatch: %+v", got)
	}
	if vh := got.Buckets[0].Content["/topic"]; vh.Ref != "" {
		t.Errorf("/topic Ref = %q, want empty", vh.Ref)
	}
	if vh := got.Buckets[0].Content["/group"]; vh.Ref != "pekko://s@h:1/user/sub" {
		t.Errorf("/group Ref = %q, want actor path", vh.Ref)
	}
}
